code_examples.insecureCode:
// ❌ Insecure: Mass assignment allows the user to change their role!
app.patch('/api/profile', (req, res) => {
  // Danger: Takes everything from req.body, including role: 'ADMIN'
  User.update(req.user.id, req.body);
  res.send('Profile updated.');
});

code_examples.secureCode:
// ✓ Secure: Explicitly defines which fields can be updated
app.patch('/api/profile', (req, res) => {
  const safeFields = {
    name: req.body.name,
    email: req.body.email
    // role is NOT included here
  };
  User.update(req.user.id, safeFields);
  res.send('Profile safely updated.');
});
